import{_ as i,o as a,c as t,a2 as l}from"./chunks/framework.C24VBsJ9.js";const c=JSON.parse('{"title":"Input 子系统按键驱动教程","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/driver/07_input_subsystem_key/index.md","filePath":"tutorial/driver/07_input_subsystem_key/index.md","lastUpdated":1779887266000}'),r={name:"tutorial/driver/07_input_subsystem_key/index.md"};function o(n,e,d,u,_,p){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="input-子系统按键驱动教程" tabindex="-1">Input 子系统按键驱动教程 <a class="header-anchor" href="#input-子系统按键驱动教程" aria-label="Permalink to &quot;Input 子系统按键驱动教程&quot;">​</a></h1><p>本教程讲解使用 Linux Input 子系统的标准按键驱动实现。Input 子系统是处理输入设备的&quot;正统&quot;方式，支持键盘、鼠标、触摸屏、游戏手柄等各种输入设备。</p><h2 id="为什么学-input-子系统" tabindex="-1">为什么学 Input 子系统 <a class="header-anchor" href="#为什么学-input-子系统" aria-label="Permalink to &quot;为什么学 Input 子系统&quot;">​</a></h2><p>在前面的教程中，我们实现了两种按键驱动：一种是简单的字符设备接口，另一种是用 poll 改进的版本。这两套方案都能用，但都有自己的问题：</p><ul><li><strong>自定义协议</strong>：设备节点和数据格式都是自定义的，应用层需要专门适配</li><li><strong>兼容性差</strong>：Qt、GTK、X11 这些框架不认识自定义设备</li><li><strong>扩展困难</strong>：多按键支持、事件类型扩展都要自己实现</li></ul><p>Input 子系统解决了这些问题：</p><ol><li><strong>标准接口</strong>：所有输入设备用统一的 API</li><li><strong>用户空间支持</strong>：X11、Wayland、Qt、GTK 直接支持</li><li><strong>自动设备管理</strong>：无需手动创建设备节点</li><li><strong>内置功能</strong>：消抖、自动重复、多按键支持</li></ol><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><ol><li><a href="./01_introduction">01_introduction.md</a> - 前言：别重复造轮子了</li><li><a href="./02_input_architecture">02_input_architecture.md</a> - Input 子系统架构</li><li><a href="./03_event_reporting">03_event_reporting.md</a> - 事件报告</li><li><a href="./04_delayed_debounce">04_delayed_debounce.md</a> - 延时消抖</li><li><a href="./05_userspace_integration">05_userspace_integration.md</a> - 用户空间集成</li><li><a href="./06_build_and_test">06_build_and_test.md</a> - 编译和测试</li></ol><h2 id="学习目标" tabindex="-1">学习目标 <a class="header-anchor" href="#学习目标" aria-label="Permalink to &quot;学习目标&quot;">​</a></h2><p>完成本教程后，你将：</p><ul><li>理解 Input 子系统的分层架构（驱动层、Input Core、Handler）</li><li>掌握 <code>input_dev</code> 的分配、配置和注册</li><li>学会使用 <code>input_report_key()</code> 和 <code>input_sync()</code> 报告事件</li><li>了解 <code>delayed_work</code> 实现可重新调度的消抖</li><li>掌握与用户空间的集成（应用程序开发）</li></ul><h2 id="教程总结" tabindex="-1">教程总结 <a class="header-anchor" href="#教程总结" aria-label="Permalink to &quot;教程总结&quot;">​</a></h2><p>Input 子系统是 Linux 输入设备的标准做法，提供了统一的事件报告接口和用户空间 API。驱动只需要调用事件报告函数，设备节点管理、事件分发都由子系统处理。</p><p>完成本教程后，你已经掌握了：</p><ul><li>Platform 驱动框架</li><li>GPIO 子系统（<code>gpiod_*</code> API）</li><li>中断和工作队列（<code>delayed_work</code>）</li><li>Input 子系统事件报告</li><li>用户空间集成（应用程序开发）</li></ul><h2 id="相关源码" tabindex="-1">相关源码 <a class="header-anchor" href="#相关源码" aria-label="Permalink to &quot;相关源码&quot;">​</a></h2><ul><li>驱动源码：<code>/home/charliechen/imx-forge/driver/19_tutorial_key_input/alpha-board/</code></li><li>设备树：<code>/home/charliechen/imx-forge/driver/device_tree/alpha-board/19_tutorial_key_input/</code></li><li>内核源码：<code>third_party/linux_mainline/drivers/input/</code></li></ul><h2 id="前置知识" tabindex="-1">前置知识 <a class="header-anchor" href="#前置知识" aria-label="Permalink to &quot;前置知识&quot;">​</a></h2><p>建议先完成以下教程：</p><ul><li><a href="./../03_platform_led_driver/">Platform LED 驱动</a> - Platform 框架基础</li><li><a href="./../05_gpio_key_driver/">GPIO 按键（轮询）</a> - GPIO 输入机制</li><li><a href="./../06_debounced_key_driver/">中断消抖按键</a> - 中断与工作队列</li></ul>',21)])])}const h=i(r,[["render",o]]);export{c as __pageData,h as default};
